--
-- distributed_tables_colocated returns true if given tables are co-located, false otherwise.
-- The function checks shard definitions, matches shard placements for given tables.
--
CREATE OR REPLACE FUNCTION pg_catalog.distributed_tables_colocated(table1 regclass,
																   table2 regclass)
RETURNS bool
LANGUAGE plpgsql
SET search_path = pg_catalog, pg_temp
AS $function$
DECLARE
	table1_colocationid int;
	table2_colocationid int;
BEGIN
	SELECT colocationid INTO table1_colocationid
	FROM pg_catalog.pg_dist_partition WHERE logicalrelid = table1;

	SELECT colocationid INTO table2_colocationid
	FROM pg_catalog.pg_dist_partition WHERE logicalrelid = table2;

	RETURN table1_colocationid = table2_colocationid;
END;
$function$;

CREATE OR REPLACE FUNCTION hdb_catalog.hdb_schema_update_event_notifier() RETURNS trigger AS
$function$
  DECLARE
    instance_id uuid;
    occurred_at timestamptz;
    invalidations json;
    curr_rec record;
  BEGIN
    instance_id = NEW.instance_id;
    occurred_at = NEW.occurred_at;
    invalidations = NEW.invalidations;
    PERFORM pg_notify('hasura_schema_update', json_build_object(
      'instance_id', instance_id,
      'occurred_at', occurred_at,
      'invalidations', invalidations
      )::text);
    RETURN curr_rec;
  END;
$function$
LANGUAGE plpgsql;

-- since we removed the foreign key constraint with hdb_catalog.hdb_table which had 'ON UPDATE CASCADE',
-- we perform the update using trigger
CREATE OR REPLACE FUNCTION hdb_catalog.event_trigger_table_name_update()
RETURNS TRIGGER
LANGUAGE PLPGSQL
AS
$$
BEGIN
  IF (NEW.table_schema, NEW.table_name) <> (OLD.table_schema, OLD.table_name)  THEN
    UPDATE hdb_catalog.event_triggers
    SET schema_name = NEW.table_schema, table_name = NEW.table_name
    WHERE (schema_name, table_name) = (OLD.table_schema, OLD.table_name);
  END IF;
  RETURN NEW;
END;
$$;

CREATE TRIGGER event_trigger_table_name_update_trigger
AFTER UPDATE ON hdb_catalog.hdb_table
FOR EACH ROW EXECUTE PROCEDURE hdb_catalog.event_trigger_table_name_update();

CREATE OR REPLACE FUNCTION
  hdb_catalog.insert_event_log(schema_name text, table_name text, trigger_name text, op text, row_data json)
  RETURNS text AS $$
  DECLARE
  id text;
  payload json;
  session_variables json;
  server_version_num int;
BEGIN
  id := gen_random_uuid();
  server_version_num := current_setting('server_version_num');
  IF server_version_num >= 90600 THEN
    session_variables := current_setting('hasura.user', 't');
  ELSE
    BEGIN
      session_variables := current_setting('hasura.user');
    EXCEPTION WHEN OTHERS THEN
      session_variables := NULL;
    END;
  END IF;
  payload := json_build_object('op', op, 'data', row_data, 'session_variables', session_variables);
  INSERT INTO hdb_catalog.event_log
    (id, schema_name, table_name, trigger_name, payload)
  VALUES (id, schema_name, table_name, trigger_name, payload);
  RETURN id;
END;
$$ LANGUAGE plpgsql;

