CREATE OR REPLACE FUNCTION pg6502.op_stxy(p_mode TEXT, p_toggle INT, p_pc INT)
RETURNS VOID AS $$
DECLARE
    v_addr INT;
    v_val  INT;
    v_size INT;
BEGIN
    CASE p_mode
        WHEN 'zero_page'   THEN v_addr := pg6502.addr_zero_page(p_pc);   v_size := 2;
        WHEN 'zero_page_y' THEN v_addr := pg6502.addr_zero_page_y(p_pc); v_size := 2;
        WHEN 'zero_page_x' THEN v_addr := pg6502.addr_zero_page_x(p_pc); v_size := 2;
        WHEN 'absolute'  THEN v_addr := pg6502.addr_absolute(p_pc);  v_size := 3;
        ELSE
            RAISE EXCEPTION 'invalid addressing mode: %', p_mode;
    END CASE;

    IF p_toggle = 0 THEN
        SELECT x INTO v_val FROM pg6502.cpu;
    ELSE
        SELECT y INTO v_val FROM pg6502.cpu;
    END IF;

    PERFORM pg6502.mem_write(v_addr, v_val);

    UPDATE pg6502.cpu
    SET pc = p_pc + v_size;
END;
$$ LANGUAGE plpgsql

-- CPX: Compare X with memory
CREATE OR REPLACE FUNCTION pg6502.op_cpx(p_mode TEXT, p_pc INT)
RETURNS VOID AS $$
DECLARE v_addr INT; v_val INT; v_x INT; v_result INT; v_size INT;
BEGIN
    CASE p_mode
        WHEN 'immediate'   THEN v_addr := pg6502.addr_immediate(p_pc);   v_size := 2;
        WHEN 'zero_page'   THEN v_addr := pg6502.addr_zero_page(p_pc);   v_size := 2;
        WHEN 'absolute'    THEN v_addr := pg6502.addr_absolute(p_pc);    v_size := 3;
    END CASE;
    v_val := pg6502.mem_read(v_addr);
    SELECT x INTO v_x FROM pg6502.cpu;
    v_result := v_x - v_val;
    UPDATE pg6502.cpu SET
        flag_c = (v_x >= v_val),
        flag_z = (v_x = v_val),
        flag_n = ((v_result & 128) != 0),
        pc     = p_pc + v_size;
END;
$$ LANGUAGE plpgsql

-- CPY: Compare Y with memory
CREATE OR REPLACE FUNCTION pg6502.op_cpy(p_mode TEXT, p_pc INT)
RETURNS VOID AS $$
DECLARE v_addr INT; v_val INT; v_y INT; v_result INT; v_size INT;
BEGIN
    CASE p_mode
        WHEN 'immediate'   THEN v_addr := pg6502.addr_immediate(p_pc);   v_size := 2;
        WHEN 'zero_page'   THEN v_addr := pg6502.addr_zero_page(p_pc);   v_size := 2;
        WHEN 'absolute'    THEN v_addr := pg6502.addr_absolute(p_pc);    v_size := 3;
    END CASE;
    v_val := pg6502.mem_read(v_addr);
    SELECT y INTO v_y FROM pg6502.cpu;
    v_result := v_y - v_val;
    UPDATE pg6502.cpu SET
        flag_c = (v_y >= v_val),
        flag_z = (v_y = v_val),
        flag_n = ((v_result & 128) != 0),
        pc     = p_pc + v_size;
END;
$$ LANGUAGE plpgsql

-- BIT: Bit test - loads value, tests bits against flags, doesn't change A (on real 6502 A is affected but flags are set from memory)
CREATE OR REPLACE FUNCTION pg6502.op_bit(p_mode TEXT, p_pc INT)
RETURNS VOID AS $$
DECLARE v_addr INT; v_val INT; v_a INT; v_size INT;
BEGIN
    CASE p_mode
        WHEN 'zero_page' THEN v_addr := pg6502.addr_zero_page(p_pc); v_size := 2;
        WHEN 'absolute'  THEN v_addr := pg6502.addr_absolute(p_pc);  v_size := 3;
    END CASE;
    v_val := pg6502.mem_read(v_addr);
    SELECT a INTO v_a FROM pg6502.cpu;
    UPDATE pg6502.cpu SET
        flag_z = ((v_a & v_val) = 0),
        flag_v = ((v_val & 64) != 0),
        flag_n = ((v_val & 128) != 0),
        pc     = p_pc + v_size;
END;
$$ LANGUAGE plpgsql

create or replace function assert.fail(
    _message text,
    _comment text
) returns boolean as $$
    declare
        _current_test_id int;
    begin

        _current_test_id = assert.get_current_test_id();

        IF _current_test_id IS NULL THEN

            RAISE EXCEPTION '%', (
                SELECT
                    CASE WHEN _comment != '' THEN
                        _message || '. ' || _comment
                    ELSE _message END
            );

        END IF;

        INSERT INTO assert.errors (
            test_id,
            error
        ) VALUES (
            _current_test_id,
            (_message, _comment)::assert.error
        );

        return false;
    end;
$$ language plpgsql security definer

-- After DELETE on storage.objects
-- - Guards with `gc.prefixes`
-- - Locks top-level prefixes for touched objects
-- - Deletes leaf prefixes derived from deleted object names and their ancestors
CREATE OR REPLACE FUNCTION storage.objects_delete_cleanup()
    RETURNS trigger
    LANGUAGE plpgsql
    SECURITY DEFINER
AS $$
DECLARE
    v_bucket_ids text[];
    v_names      text[];
BEGIN
    IF current_setting('storage.gc.prefixes', true) = '1' THEN
        RETURN NULL;
    END IF;

    PERFORM set_config('storage.gc.prefixes', '1', true);

    SELECT COALESCE(array_agg(d.bucket_id), '{}'),
           COALESCE(array_agg(d.name), '{}')
    INTO v_bucket_ids, v_names
    FROM deleted AS d
    WHERE d.name <> '';

    PERFORM storage.lock_top_prefixes(v_bucket_ids, v_names);
    PERFORM storage.delete_leaf_prefixes(v_bucket_ids, v_names);

    RETURN NULL;
END;
$$

-- After DELETE on storage.prefixes
-- - When prefixes are deleted, remove now-empty ancestor prefixes
-- - Guards with `gc.prefixes`, locks, then prunes leaves derived from deleted prefixes
CREATE OR REPLACE FUNCTION storage.prefixes_delete_cleanup()
    RETURNS trigger
    LANGUAGE plpgsql
    SECURITY DEFINER
AS $$
DECLARE
    v_bucket_ids text[];
    v_names      text[];
BEGIN
    IF current_setting('storage.gc.prefixes', true) = '1' THEN
        RETURN NULL;
    END IF;

    PERFORM set_config('storage.gc.prefixes', '1', true);

    SELECT COALESCE(array_agg(d.bucket_id), '{}'),
           COALESCE(array_agg(d.name), '{}')
    INTO v_bucket_ids, v_names
    FROM deleted AS d
    WHERE d.name <> '';

    PERFORM storage.lock_top_prefixes(v_bucket_ids, v_names);
    PERFORM storage.delete_leaf_prefixes(v_bucket_ids, v_names);

    RETURN NULL;
END;
$$

-- delete_parent_counts removes all resource counts for a deleted parent.
-- 1. The type of the parent
-- 2. The column name of the instance id
-- 3. The column name of the owner id
CREATE OR REPLACE FUNCTION projections.delete_parent_counts()
	RETURNS trigger
	LANGUAGE 'plpgsql'
AS $$
DECLARE
	-- trigger variables
	tg_parent_type TEXT := TG_ARGV[0];
	tg_instance_id_column TEXT := TG_ARGV[1];
	tg_parent_id_column TEXT := TG_ARGV[2];

	tg_instance_id TEXT;
	tg_parent_id TEXT;

	select_ids TEXT := format('SELECT ($1).%I, ($1).%I', tg_instance_id_column, tg_parent_id_column);
BEGIN
	EXECUTE select_ids INTO tg_instance_id, tg_parent_id USING OLD;

	DELETE FROM projections.resource_counts
		WHERE instance_id = tg_instance_id
		AND parent_type = tg_parent_type
		AND parent_id = tg_parent_id;

	RETURN OLD;
END
$$

