CREATE FUNCTION git_object_write(
    p_repo_id integer,
    p_type smallint,
    p_content bytea
)
RETURNS bytea
LANGUAGE plpgsql AS $$
DECLARE
    v_oid bytea;
BEGIN
    v_oid := git_object_hash(p_type, p_content);

    INSERT INTO objects (repo_id, oid, type, size, content)
    VALUES (p_repo_id, v_oid, p_type, octet_length(p_content), p_content)
    ON CONFLICT (repo_id, oid) DO NOTHING;

    RETURN v_oid;
END;
$$

-- INC: Increment a memory location
CREATE OR REPLACE FUNCTION pg6502.op_inc(p_mode TEXT, p_pc INT)
RETURNS VOID AS $$
DECLARE v_addr INT; v_val INT; v_size INT;
BEGIN
    CASE p_mode
        WHEN 'zero_page'   THEN v_addr := pg6502.addr_zero_page(p_pc);   v_size := 2;
        WHEN 'zero_page_x' THEN v_addr := pg6502.addr_zero_page_x(p_pc); v_size := 2;
        WHEN 'absolute'    THEN v_addr := pg6502.addr_absolute(p_pc);     v_size := 3;
        WHEN 'absolute_x'  THEN v_addr := pg6502.addr_absolute_x(p_pc);  v_size := 3;
    END CASE;
    v_val := (pg6502.mem_read(v_addr) + 1) & 255;
    PERFORM pg6502.mem_write(v_addr, v_val);
    UPDATE pg6502.cpu SET pc = p_pc + v_size;
    PERFORM pg6502.set_nz(v_val);
END;
$$ LANGUAGE plpgsql

-- DEC: Decrement a memory location
CREATE OR REPLACE FUNCTION pg6502.op_dec(p_mode TEXT, p_pc INT)
RETURNS VOID AS $$
DECLARE v_addr INT; v_val INT; v_size INT;
BEGIN
    CASE p_mode
        WHEN 'zero_page'   THEN v_addr := pg6502.addr_zero_page(p_pc);   v_size := 2;
        WHEN 'zero_page_x' THEN v_addr := pg6502.addr_zero_page_x(p_pc); v_size := 2;
        WHEN 'absolute'    THEN v_addr := pg6502.addr_absolute(p_pc);     v_size := 3;
        WHEN 'absolute_x'  THEN v_addr := pg6502.addr_absolute_x(p_pc);  v_size := 3;
    END CASE;
    v_val := (pg6502.mem_read(v_addr) + 255) & 255;  -- +255 wraps correctly (avoids negative)
    PERFORM pg6502.mem_write(v_addr, v_val);
    UPDATE pg6502.cpu SET pc = p_pc + v_size;
    PERFORM pg6502.set_nz(v_val);
END;
$$ LANGUAGE plpgsql

-- BRK: Software Interrupt - push PC+2, status, and jump to interrupt vector
CREATE OR REPLACE FUNCTION pg6502.op_brk()
RETURNS VOID AS $$
DECLARE v_pc INT; v_flags INT; v_lo INT; v_hi INT; v_vector INT;
BEGIN
    SELECT pc INTO v_pc FROM pg6502.cpu;
    v_pc := v_pc + 2; -- BRK is 2 bytes, PC points past it

    v_lo := v_pc & 255;
    v_hi := (v_pc >> 8) & 255;

    PERFORM pg6502.stack_push(v_hi);
    PERFORM pg6502.stack_push(v_lo);

    v_flags := pg6502.flags_to_byte();
    v_flags := v_flags | 16; -- set B flag
    PERFORM pg6502.stack_push(v_flags);

    v_vector := pg6502.mem_read16(65532);
    UPDATE pg6502.cpu SET pc = v_vector, flag_i = TRUE;
END;
$$ LANGUAGE plpgsql

CREATE OR REPLACE FUNCTION pg6502.run(p_max_cycles INT DEFAULT 100000, p_log_interval INT DEFAULT 1000000)
RETURNS INT AS $$
DECLARE
    v_result TEXT;
    v_cycles INT := 0;
    v_pc INT;
BEGIN
    LOOP
        v_result := pg6502.execute_instruction();
        v_cycles := v_cycles + 1;

        IF v_cycles % p_log_interval = 0 THEN
            SELECT pc INTO v_pc FROM pg6502.cpu;
            RAISE NOTICE 'Cycles: %, PC: %', v_cycles, v_pc;
        END IF;

        EXIT WHEN v_result = 'BRK';
        EXIT WHEN v_cycles >= p_max_cycles;
    END LOOP;

    RETURN v_cycles;
END;
$$ LANGUAGE plpgsql

-- Load a program from a bytea value into memory starting at p_start.
-- Also writes the reset vector at $FFFC pointing to p_start.
CREATE OR REPLACE FUNCTION pg6502.load_program(p_bytes BYTEA, p_start INT DEFAULT 1536)
RETURNS VOID AS $$
DECLARE
    i INT;
BEGIN
    -- Clear existing memory
    DELETE FROM pg6502.mem;

    -- Write each byte
    FOR i IN 0 .. length(p_bytes) - 1 LOOP
        PERFORM pg6502.mem_write(p_start + i, get_byte(p_bytes, i));
    END LOOP;

    -- Write reset vector (little-endian)
    PERFORM pg6502.mem_write(65532, p_start & 255);
    PERFORM pg6502.mem_write(65533, (p_start >> 8) & 255);
END;
$$ LANGUAGE plpgsql

CREATE FUNCTION sql_step(p_job_id bigint, p_action text, p_sql text) RETURNS boolean
    LANGUAGE plpgsql
    AS $$
DECLARE
    v_step_id   bigint;
    v_numrows   bigint;
BEGIN
    v_step_id := @extschema@.add_step(p_job_id, p_action);
    EXECUTE p_sql;
    GET DIAGNOSTICS v_numrows = ROW_COUNT;
    PERFORM @extschema@.update_step(v_step_id, 'OK', 'Rows affected: ' || v_numrows);
    PERFORM @extschema@.close_job(p_job_id);

    RETURN true;
EXCEPTION
    WHEN OTHERS THEN
        PERFORM @extschema@.update_step(v_step_id, 'CRITICAL', 'ERROR: '||coalesce(SQLERRM,'unknown'));
        RETURN false;
END
$$

-- This replicates the old behavior of recurrence.Recurrence
CREATE OR REPLACE FUNCTION om_func_get_go_normalized_last_iteration_not_after_cutoff(
    anchor TIMESTAMPTZ,
    duration INTERVAL,
    cutoff TIMESTAMPTZ
) RETURNS TIMESTAMPTZ AS $$
DECLARE
    result_ts TIMESTAMPTZ;
    iter_ts TIMESTAMPTZ;
BEGIN
    result_ts = anchor;
    iter_ts = anchor;

    IF result_ts <= cutoff THEN
        -- We iterate onwards
        WHILE iter_ts <= cutoff LOOP
            result_ts = iter_ts;

            iter_ts = om_func_go_add_date_normalized(iter_ts, duration);
        END LOOP;
    ELSE
        -- We iterate backwards
        WHILE iter_ts > cutoff LOOP
            iter_ts = om_func_go_add_date_normalized(iter_ts, -duration);

            result_ts = iter_ts;
        END LOOP;
    END IF;

    return result_ts;
END;
$$ LANGUAGE plpgsql VOLATILE

CREATE OR REPLACE FUNCTION pg_show_activity()
    RETURNS TEXT AS $$
DECLARE
    records     RECORD;
    queryString TEXT;
	returnData  TEXT DEFAULT '';
BEGIN
    queryString := 'select * from pg_stat_activity';
    FOR records IN EXECUTE queryString LOOP
    	returnData := returnData || ''||
    		'datname: '|| rpad(records.datname, 40, ' ') ||
           	' | pid: ' || rpad(records.pid::text, 6, ' ') ||
           	' | usename: ' || rpad(records.usename, 20, ' ') ||
           	' | application: '|| rpad(records.application_name, 25, ' ') ||
           	' | state: ' || rpad(records.state, 21, ' ') || '\n';
    END LOOP;
    RETURN returnData;
END;
$$ LANGUAGE plpgsql

CREATE OR REPLACE FUNCTION pg_show_size_databases() RETURNS CHARACTER VARYING AS $$
DECLARE
    queryString TEXT;
    returnData  TEXT DEFAULT '';
    records     RECORD;
BEGIN
    queryString := '' ||
               'SELECT ' ||
                   'datname, ' ||
                   'pg_size_pretty(pg_database_size(datname))  ' ||
               'FROM pg_database ' ||
                   'WHERE ' ||
                        'datistemplate = false ' ||
                        'ORDER BY pg_size_pretty';

    FOR records IN EXECUTE queryString LOOP

    	returnData := returnData || ''||
            'Database: '|| rpad(records.datname, 60, ' ') ||
            ' | Size: ' || rpad(records.pg_size_pretty, 12, ' ') || '\n';

    END LOOP;

    RETURN returnData;
END;
$$ LANGUAGE plpgsql

CREATE OR REPLACE FUNCTION pgmq.notify_queue_listeners()
RETURNS TRIGGER AS $$
DECLARE
  queue_name_extracted TEXT; -- Queue name extracted from trigger table name
  updated_count        INTEGER; -- Number of rows updated (0 or 1)
BEGIN
  queue_name_extracted := substring(TG_TABLE_NAME from 3);

  UPDATE pgmq.notify_insert_throttle
  SET last_notified_at = clock_timestamp()
  WHERE queue_name = queue_name_extracted
    AND (
      throttle_interval_ms = 0 -- No throttling configured
          OR clock_timestamp() - last_notified_at >=
             (throttle_interval_ms * INTERVAL '1 millisecond') -- Throttle interval has elapsed
    );

  -- Check how many rows were updated (will be 0 or 1)
  GET DIAGNOSTICS updated_count = ROW_COUNT;

  IF updated_count > 0 THEN
    PERFORM PG_NOTIFY('pgmq.' || TG_TABLE_NAME || '.' || TG_OP, NULL);
  END IF;

RETURN NEW;
END;
$$ LANGUAGE plpgsql;

